"""Status d'une commande."""


class STATUS:
    """Code de status d'une commande terminée.

    L'utilisateur peut utiliser les codes de 2 à 63.
    Les status SIG_* sont initialement dues à la réception d'un signal.
    """

    # Valeurs limites
    MIN = 0
    """Valeur minimale."""

    MAX = 255
    """Valeur maximale."""

    # Status génériques:
    SUCCESS = 0
    """Succès."""

    FAILURE = 1
    """Erreur générique."""

    # Status pour les programmes systèmes:
    # cf. `man sysexits.h`
    USAGE = 64
    """Mauvaise utilisation de la commande."""

    DATA_ERR = 65
    """Mauvais format de données en entrée."""

    NO_INPUT = 66
    """Pas de données en entrée (fichier introuvable)."""

    NO_USER = 67
    """Utilisateur introuvable."""

    NO_HOST = 68
    """Hôte introuvable."""

    UNAVAILABLE = 69
    """Service indisponible."""

    SOFTWARE_ERR = 70
    """Erreur logicielle (hors OS)."""

    OS_ERR = 71
    """Erreur du système d'exploitation."""

    OS_FILE_ERR = 72
    """Erreur dans un fichier du système d'exploitation."""

    CANT_CREATE = 73
    """Impossible de créer le fichier de sortie."""

    IO_ERR = 74
    """Erreur d'entrée/sortie."""

    TEMP_FAIL = 75
    """Erreur temporaire, réessayez."""

    PROTOCOL_ERR = 76
    """Non respect du protocole."""

    NO_PERM = 77
    """Pas de permission pour l'opération demandée."""

    CONFIG_ERR = 78
    """Erreur de configuration."""

    # Status pour les scripts:
    # cf. le manuel Bash https://tldp.org/LDP/abs/html/exitcodes.html
    NOT_EXECUTABLE = 126
    """Commande non exécutable."""

    NOT_FOUND = 127
    """Commande introuvable."""

    # Status lors de la réception d'un signal:
    # Le manuel Bash définie un code de status 128 à partir duquel est ajouté
    # le numéro du signal.
    SIG_HUP = 129
    """Hangup: Connexion interrompue (terminal fermé)."""

    SIG_INT = 130
    """Interrupt: Programme interrompu par Ctrl-C."""

    SIG_QUIT = 131
    """Quit: Sortie du programme par Ctrl-D."""

    SIG_ILL = 132
    """Illegal: Instruction illégale."""

    SIG_TRAP = 133
    """Trap: Point d'arrêt pour débogage."""

    SIG_ABRT = 134
    """Abort: Fin anormale du programme."""

    SIG_BUS = 135
    """Bus: Erreur de bus de données."""

    SIG_FPE = 136
    """Floating Point Exception: Opération mathématique illégale."""

    SIG_KILL = 137
    """Killed: Terminaison forcée du programme."""

    SIG_USR1 = 138
    """User 1: Signal utilisateur 1."""

    SIG_SEGV = 139
    """Segmentation Fault: Erreur de segmentation mémoire."""

    SIG_USR2 = 140
    """User 2: Signal utilisateur 2."""

    SIG_PIPE = 141
    """Pipe: Pipe interrompu."""

    SIG_ALRM = 142
    """Alarm: Alarme utilisateur expirée."""

    SIG_TERM = 143
    """Terminated: Terminaison du processus."""

    SIG_STKFLT = 144
    """Stack Fault: Erreur de pile du coprocesseur."""

    SIG_CHLD = 145
    """Child: Arrêt ou fin du processus fils."""

    SIG_CONT = 146
    """Continue: Reprise du processus."""

    SIG_STOP = 147
    """Stop: Mise en pause du processus."""

    SIG_TSTP = 148
    """Terminal Stop: Mise en pause du processus depuis le terminal par Ctrl-Z."""  # noqa: E501

    SIG_TTIN = 149
    """TTY Input: Le processus en arrière plan veut lire depuis le terminal."""

    SIG_TTOU = 150
    """TTY Output: Le processus en arrière plan veut écrire dans le terminal."""  # noqa: E501

    SIG_URG = 151
    """Urgent: Données urgentes à lire sur le socket."""

    SIG_XCPU = 152
    """Exceed CPU: Dépassement de la limite d'utilisation du CPU."""

    SIG_XFSZ = 153
    """Exceed File Size: Dépassement de la limite de taille d'un fichier."""

    SIG_VTALRM = 154
    """Virtual Timer Alarm: Alarme virtuelle expirée."""

    SIG_PROF = 155
    """Profiling: Minuteur du profilage expiré."""

    SIG_WINCH = 156
    """Window Change: Redimensionnement de la fenêtre."""

    SIG_IO = 157
    """Input/Output: Entrée/sortie disponible."""

    SIG_PWR = 158
    """Power: Problème d'alimentation/redémarrage."""

    SIG_SYS = 159
    """System: Mauvais appel système."""
